import React from "react";
import CIcon from "@coreui/icons-react";
import { cilAccountLogout, cilBorderAll, cilUser } from "@coreui/icons";
import { CNavGroup, CNavItem } from "@coreui/react";

// Helper function to create a menu item
const createNavItem = (component, name, to, icon) => ({
  component,
  name,
  to,
  icon: <CIcon icon={icon} customClassName="nav-icon" />,
});

const menuList = [
  createNavItem(CNavItem, "Dashboard", "/dashboard", cilBorderAll),
  createNavItem(CNavItem, "Colleges", "/colleges", cilUser),
  createNavItem(CNavItem, "Logout", "/logout", cilAccountLogout),
];

export default menuList;
